import React, {type PropsWithChildren} from "react";
import {Platform} from "react-native";
import {ResponsiveElement, useSeparator} from "../../../../Factory";
import type {ElementProps, IFlexComponent} from "@lmb-it/kitsconcerto-types";


const Flex = ({ className, children, ref, ...props }:PropsWithChildren<IFlexComponent>) => {
    const { cssProps, nativeProps } = useSeparator<Record<any, any>>(props);
    const { scrollable, entering, exiting, ...restNativeProps } = nativeProps;

    const animProps = { entering, exiting };

    if (restNativeProps.onClick && typeof restNativeProps.onClick == 'function' && Platform.OS != 'web') {
        return (
            <ResponsiveElement<ElementProps>
                ref={ref}
                scrollable={scrollable}
                {...animProps}
                additionalStyles={{
                    display: "flex",
                    flexDirection: "row",
                }}
                additionalClasses={className}
                cssProps={cssProps}
                nativeProps={restNativeProps}
                children={<ResponsiveElement<any>
                    additionalStyles={{
                        width: '100%',
                        height: '100%',
                        position: 'relative'
                    }}
                    as={'a'}
                    nativeProps={{
                        onClick: restNativeProps.onClick
                    }}
                    children={children}
                    cssProps={{}}
                />}
            />
        );
    }

    return (
        <ResponsiveElement
            ref={ref}
            scrollable={scrollable}
            {...animProps}
            additionalStyles={{
                display: "flex",
                flexDirection: "row",
            }}
            additionalClasses={className}
            cssProps={cssProps}
            nativeProps={restNativeProps}
            children={children}
        />
    );
}
Flex.displayName = "Flex";
export default Flex;
